/**
 * @brief ppoll() - wait for events on file descriptors
 * @property int ppoll(struct pollfd *fds, nfds_t nfds,
        const struct timespec *timeout_ts, const sigset_t *sigmask);
 * @return On success, ppoll() returns the number of file descriptors
       ready for reading or writing, or 0 if the timeout expired.  On
       error, -1 is returned, and errno is set to indicate the error.
 */
uint64 sys_ppoll() {
    uint64 fds_addr;
    uint64 nfds;
    uint64 timeout_ts_addr;
    uint64 sigmask_addr;
    struct proc *p = myproc();
    struct kernel_pollfd *pfds = NULL;
    struct timespec timeout;
    uint64 ready = 0;
    argaddr(0, &fds_addr);
    argaddr(1, &nfds);
    argaddr(2, &timeout_ts_addr);
    argaddr(3, &sigmask_addr);
    (void)sigmask_addr;

    if(nfds > NOFILE) {
        return -EINVAL;
    }
    if(nfds == 0) {
        if(timeout_ts_addr) {
            if(copyin(p->mm.pagetable, (char *)&timeout, timeout_ts_addr, sizeof(timeout)) < 0) {
                return -EFAULT;
            }
            if(timeout.tv_sec < 0 || timeout.tv_nsec >= 1000000000ULL) {
                return -EINVAL;
            }
            acquire(&tickslock);
            if(timeout.tv_sec != 0 || timeout.tv_nsec != 0) {
                thread_sleep(&ticks, &tickslock, &timeout);
            }
            release(&tickslock);
        }
        return 0;
    }

    pfds = (struct kernel_pollfd *)kmalloc(sizeof(*pfds) * nfds);
    if(pfds == NULL) {
        return -ENOMEM;
    }
    if(copyin(p->mm.pagetable, (char *)pfds, fds_addr, sizeof(*pfds) * nfds) < 0) {
        kfree(pfds);
        return -EFAULT;
    }
    for(uint64 i = 0; i < nfds; i++) {
        pfds[i].revents = 0;
        if(pfds[i].fd < 0) {
            continue;
        }
        if(pfds[i].fd >= NOFILE || p->ofile[pfds[i].fd] == NULL) {
            pfds[i].revents = POLLNVAL;
            ready++;
            continue;
        }
        if(pfds[i].events & (POLLIN | POLLPRI)) {
            pfds[i].revents |= POLLIN;
        }
        if(pfds[i].events & POLLOUT) {
            pfds[i].revents |= POLLOUT;
        }
        if(pfds[i].revents != 0) {
            ready++;
        }
    }
    if(copyout(p->mm.pagetable, fds_addr, (char *)pfds, sizeof(*pfds) * nfds) < 0) {
        kfree(pfds);
        return -EFAULT;
    }
    if(ready == 0 && timeout_ts_addr) {
        if(copyin(p->mm.pagetable, (char *)&timeout, timeout_ts_addr, sizeof(timeout)) < 0) {
            kfree(pfds);
            return -EFAULT;
        }
        if(timeout.tv_sec < 0 || timeout.tv_nsec >= 1000000000ULL) {
            kfree(pfds);
            return -EINVAL;
        }
        acquire(&tickslock);
        if(timeout.tv_sec != 0 || timeout.tv_nsec != 0) {
            thread_sleep(&ticks, &tickslock, &timeout);
        }
        release(&tickslock);
    }
    kfree(pfds);
    return ready;
}


