static int procfs_unlink(const char *path, int flags){
    (void)flags;
    if(procfs_lookup(path) == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    return -EROFS;
}

int procfs_rename(const char *oldpath, const char *newpath) {
    (void)newpath;
    if(procfs_lookup(oldpath) == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    return -EROFS;
}

static int procfs_read(struct file *fp, int user_dst, uint64 dst, int64_t off, size_t size, size_t *rcnt) {
    enum procfs_node_kind node = procfs_lookup(fp->info.path);
    char *buf;
    int len;
    size_t nread;

    if(node == PROCFS_NODE_DIR_ROOT) {
        return -EISDIR;
    }
    if(node == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    if((buf = kmalloc(PGSIZE)) == NULL) {
        return -ENOMEM;
    }
    len = procfs_render_file(node, buf, PGSIZE);
    if(len < 0) {
        kfree(buf);
        return len;
    }
    if(off >= len) {
        *rcnt = 0;
        fp->fpos = off;
        kfree(buf);
        return 0;
    }

    nread = size;
    if(off + nread > (size_t)len) {
        nread = len - off;
    }
    if(procfs_emit_bytes(user_dst, dst, buf + off, nread) < 0) {
        kfree(buf);
        return -EFAULT;
    }
    fp->fpos = off + nread;
    *rcnt = nread;
    kfree(buf);
    return 0;
}

static int procfs_write(struct file *fp, int user_src, uint64 src, int64_t off, size_t size, size_t *wcnt) {
    (void)user_src;
    (void)src;
    (void)off;
    (void)size;
    (void)wcnt;
    if(procfs_lookup(fp->info.path) == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    return -EROFS;
}

static int procfs_open(struct file *fp, const char *path, int flags) {
    enum procfs_node_kind node = procfs_lookup(path);

    (void)flags;
    if(node == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    fp->type = node == PROCFS_NODE_DIR_ROOT ? FD_DIR : FD_SPEC;
    fp->fpos = 0;
    return 0;
}

static int procfs_close(struct file *fp) {
    (void)fp;
    return 0;
}

static int procfs_getdents(struct file *fp, struct linux_dirent64 *dirp, int count) {
    struct linux_dirent64 *d = dirp;
    int total = 0;

    if(procfs_lookup(fp->info.path) != PROCFS_NODE_DIR_ROOT) {
        return -ENOTDIR;
    }
    for(int index = fp->fpos; index < NELEM(procfs_root_entries); index++) {
        int namelen = strlen(procfs_root_entries[index].name);
        int reclen = sizeof(struct linux_dirent64) + namelen + 1;
        if(total + reclen > count) {
            break;
        }
        d->d_ino = index + 1;
        d->d_off = index + 1;
        d->d_reclen = reclen;
        d->d_type = procfs_root_entries[index].type;
        strcpy(d->d_name, procfs_root_entries[index].name);
        total += reclen;
        d = (struct linux_dirent64 *)((char *)d + reclen);
        fp->fpos = index + 1;
    }
    return total;
}

static int procfs_fstat(char *path, struct kstat *kst) {
    enum procfs_node_kind node = procfs_lookup(path);

    if(node == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    if(node == PROCFS_NODE_DIR_ROOT) {
        procfs_fill_kstat(kst, S_IFDIR | 0555, 0);
    } else {
        procfs_fill_kstat(kst, S_IFREG | 0444, 0);
    }
    return 0;
}

static int procfs_isdir(const char *path) {
    return procfs_lookup(path) == PROCFS_NODE_DIR_ROOT;
}

static int procfs_faccess(char *path, int amode, int flags) {
    (void)flags;
    if(procfs_lookup(path) == PROCFS_NODE_NONE) {
        return -ENOENT;
    }
    if(amode & W_OK) {
        return -EROFS;
    }
    return 0;
}

static int procfs_statfs(struct vfs_filesystem *fs, struct statfs *buf) {
    (void)fs;
    memset(buf, 0, sizeof(*buf));
    buf->f_type = PROC_SUPER_MAGIC;
    buf->f_bsize = 1024;
    buf->f_blocks = 1;
    buf->f_bfree = 1;
    buf->f_bavail = 1;
    buf->f_files = NELEM(procfs_root_entries);
    buf->f_frsize = 1024;
    buf->f_namelen = 255;
    return 0;
}

static int procfs_file_exist(const char *path) {
    return procfs_lookup(path) != PROCFS_NODE_NONE;
}

static enum procfs_node_kind procfs_lookup(const char *path) {
    if(strcmp(path, "/proc") == 0 || strcmp(path, "/proc/") == 0) {
        return PROCFS_NODE_DIR_ROOT;
    }
    if(strcmp(path, "/proc/interrupts") == 0) {
        return PROCFS_NODE_INTERRUPTS;
    }
    if(strcmp(path, "/proc/meminfo") == 0) {
        return PROCFS_NODE_MEMINFO;
    }
    if(strcmp(path, "/proc/mounts") == 0) {
        return PROCFS_NODE_MOUNTS;
    }
    if(strcmp(path, "/proc/uptime") == 0) {
        return PROCFS_NODE_UPTIME;
    }
    return PROCFS_NODE_NONE;
}

static int procfs_render_file(enum procfs_node_kind node, char *buf, size_t buflen) {
    size_t len = 0;
    uint64 uptime = TIME2SEC(r_time());
    unsigned long mem_total_kb = (unsigned long)(totalram_bytes() / 1024);
    unsigned long mem_free_kb = (unsigned long)(freemem_bytes() / 1024);

    switch(node) {
        case PROCFS_NODE_INTERRUPTS:
