void
initsleeplock(struct sleeplock *lk, char *name)
{
  initlock(&lk->lk, "sleep lock");
  lk->name = name;
  lk->locked = 0;
  lk->pid = 0;
}

void
acquiresleep(struct sleeplock *lk)
{
  acquire(&lk->lk);

  // sleep时 lk->lk已经被释放
  // 多线程对sleeplock不会因为spinlock而阻塞
  while (lk->locked) {
    // sleep 等待获取锁lk
#ifdef __DEBUG_SLEEPLOCK
  int iswaken = 1;
    if(iswaken)
      Info("acquiresleep %p\n", lk);
      iswaken = 0;
#endif

    thread_sleep(lk, &lk->lk, NULL);
  }
#ifdef __DEBUG_SLEEPLOCK
  Info("acuiresleep wakeup %p\n", lk);
  iswaken = 1;
#endif

  // sleeplock 被spinlock保护
  lk->locked = 1;
  lk->pid = myproc()->pid;
  release(&lk->lk);
}

void
releasesleep(struct sleeplock *lk)
{
  acquire(&lk->lk);
  lk->locked = 0;
  lk->pid = 0;
#ifdef __DEBUG_SLEEPLOCK
  Info("releasesleep %p\n", lk);
#endif
  thread_wakeup_chan(lk);
  release(&lk->lk);
}

// check 当前 进程是否持有lk
int
holdingsleep(struct sleeplock *lk)
{
  int r;

  acquire(&lk->lk);
  r = lk->locked && (lk->pid == myproc()->pid);
  release(&lk->lk);
  return r;
}

#include "cond.h"
#include "semaphore.h"

/// @brief init a semaphore
/// @param s semaphore
/// @param value semaphore's value 
/// @param name semaphore's name
void sema_init(sem *s, int value, char *name) {
    s->value = value;
    s->wakeup = 0;
    initlock(&s->sem_lock, name);
    cond_init(&s->sem_cond, name);
}

/// @brief wait a semaphore (P operation)
/// @param s semaphore waitting on
void sema_wait(sem *s) {
    acquire(&s->sem_lock);
    s->value--;
    if (s->value < 0) {
        do {
            cond_wait(&s->sem_cond, &s->sem_lock);
        } while (s->wakeup == 0);
        s->wakeup--;
    }
    release(&s->sem_lock);
}


/// @brief signal a semaphore (V operation)
/// @param s  semaphore signaling
void sema_signal(sem *s) {
    acquire(&s->sem_lock);
    s->value++;
    if (s->value <= 0) {
        s->wakeup++;
        cond_signal(&s->sem_cond);
    }
    release(&s->sem_lock);
}

