  // if(is_exc_rcfile(p)) {
  //   Warn("fdalloc_spec: too many open files, ofile_cnt %d, rlim %d", p->ofile_cnt, p->rlim[RLIMIT_NOFILE].rlim_cur);
  //   return -EMFILE; // Too many open files
  // }
  if(p->ofile[spec_fd] != 0) {
    fileclose(p->ofile[spec_fd], 1);
    p->ofile[spec_fd] = 0;
  }
  p->ofile[spec_fd] = f;
  p->ofile_cnt++;
#ifdef __DEBUG_FDALLOC_SPEC
  Log("++ofile_cnt %d", p->ofile_cnt);
#endif
  return spec_fd;
}

static void get_abpath_from_dirfd(__nullable const char* path, int dirfd, char* abs_path) {
  struct proc *p = myproc();
  const char *dirpath = dirfd == AT_FDCWD ? p->cinfo.path : p->ofile[dirfd]->info.path;
  get_absolute_path(path, dirpath, abs_path);
}

uint64
sys_dup(void)
{
  struct file *f;
  int fd;

  if(argfd(0, 0, &f) < 0)
    return -1;
  if((fd = fdalloc(f)) < 0)
    return fd;
  filedup(f);
  return fd;
}

